DELIMITER $$
CREATE TRIGGER `actualizar_ultimo_mensaje` AFTER INSERT ON `chat_mensaje` FOR EACH ROW BEGIN
    VALUES (CONCAT('CH-', NEW.idCita), NEW.idCita, NEW.contenido, CURRENT_TIMESTAMP)
    ON DUPLICATE KEY UPDATE 
    `ultimo_mensaje` = NEW.contenido,
    `fecha_actualizacion` = CURRENT_TIMESTAMP;
END
$$
DELIMITER ;

